import { PriorityQueue } from 'typescript-collections';

function solve(n, edges) {
    // Build adjacency list
    const adj = new Array(n).fill(null).map(() => new Array());
    for (const [u, v, start, end] of edges) {
        adj[u].push({ v, start, end });
    }

    // Dijkstra's algorithm with priority queue
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;
    const pq = new PriorityQueue((a, b) => a.time - b.time);
    pq.enqueue({ node: 0, time: 0 });

    while (!pq.isEmpty()) {
        const { node, time } = pq.dequeue();
        if (node === n - 1) break;
        if (time > dist[node]) continue;

        // Try to move along each edge
        for (const { v, start, end } of adj[node]) {
            // Check if the edge is available at current time
            if (time >= start && time <= end) {
                // We can take the edge, move to v at time + 1
                const newTime = time + 1;
                if (newTime < dist[v]) {
                    dist[v] = newTime;
                    pq.enqueue({ node: v, time: newTime });
                }
            }
        }

        // Option to stay at current node
        if (time < dist[node]) {
            dist[node] = time;
            pq.enqueue({ node: node, time: time });
        }
    }

    return dist[n - 1] === Infinity ? -1 : dist[n - 1];
}

